sys_script.script:
(function executeRule(current, previous /*null when async*/) {

	// Add your code here

	// Initialize GlideRecord for the Workspace Option table
	var workspaceGr = new GlideRecord("x_1759267_wrm_workspace_options");

	// Check if the reservation status is Pending Check In or Checked In
	if (current.reservation_status == "pending_check_in" || current.reservation_status == "checked_in") {
		// Get the current workspace
		if (workspaceGr.get("sys_id", current.workspace)) {
			// Update value to unavailable
			workspaceGr.status = "unavailable";
			workspaceGr.update();
			return;
		} else {
			gs.error("BR - Reservations Sync Workspace Options: Unable to get current workspace details to update value");
		}

	} else {
		// Get the current workspace
		if (workspaceGr.get("sys_id", current.workspace)) {
			// Update value to available
			workspaceGr.status = "available";
			workspaceGr.update();
			return;
		} else {
			gs.error("BR - Reservations Sync Workspace Options: Unable to get current workspace details to update value");
		}

	}

})(current, previous);
